"""Playwright driver for the Clawrium GUI walkthrough demo."""
from __future__ import annotations

import subprocess
import sys
import time
from pathlib import Path

from playwright.sync_api import Page, sync_playwright


DEMO_DIR = Path(__file__).resolve().parent
VIEWPORT = {"width": 1400, "height": 900}
BASE_URL = 'http://127.0.0.1:36000'
COLOR_SCHEME = 'light'
REDUCED_MOTION = 'reduce'


def main() -> int:
    video_dir = DEMO_DIR / "_video_raw"
    video_dir.mkdir(exist_ok=True)
    for old in video_dir.glob("*.webm"):
        old.unlink()

    with sync_playwright() as pw:
        browser = pw.chromium.launch(headless=True, channel="chrome")
        context = browser.new_context(
            viewport=VIEWPORT,
            record_video_dir=str(video_dir),
            record_video_size=VIEWPORT,
            color_scheme=COLOR_SCHEME,
            reduced_motion=REDUCED_MOTION,
        )
        page = context.new_page()


        # ---- intro title card ----
        title_uri = (DEMO_DIR / "cards" / "title.html").as_uri()
        page.goto(title_uri, wait_until="domcontentloaded")
        page.wait_for_timeout(5000)


        # ---- initial app load ----
        page.goto(BASE_URL.rstrip("/") + "/", wait_until="domcontentloaded")
        page.wait_for_timeout(500)

        # ---- scenes ----

        play_scene_01(page)

        play_scene_02(page)

        play_scene_03(page)

        play_scene_04(page)

        play_scene_05(page)

        play_scene_06(page)

        play_scene_07(page)



        # ---- outro card ----
        outro_uri = (DEMO_DIR / "cards" / "outro.html").as_uri()
        page.goto(outro_uri, wait_until="domcontentloaded")
        page.wait_for_timeout(6000)


        context.close()
        browser.close()

    return finalize_recording()



def play_scene_01(page: Page) -> None:
    """[scene 01] Dashboard"""
    print('[scene 01] Dashboard', flush=True)
    start = time.monotonic()

    page.locator("h1:has-text('Dashboard')").first.wait_for(timeout=10_000)

    elapsed = time.monotonic() - start
    remaining = max(0.0, 9.0 - elapsed)
    page.wait_for_timeout(int(remaining * 1000))



def play_scene_02(page: Page) -> None:
    """[scene 02] Agents"""
    print('[scene 02] Agents', flush=True)
    start = time.monotonic()

    page.locator("aside nav a[href='/agents']").first.click()

    page.wait_for_url('**/agents', timeout=10_000)

    page.locator('h1').first.wait_for(timeout=10_000)

    elapsed = time.monotonic() - start
    remaining = max(0.0, 8.0 - elapsed)
    page.wait_for_timeout(int(remaining * 1000))



