def finalize_recording() -> int:
    video_dir = DEMO_DIR / "_video_raw"
    webms = sorted(video_dir.glob("*.webm"))
    if not webms:
        print("ERROR: Playwright produced no WebM", file=sys.stderr)
        return 1
    target_webm = DEMO_DIR / "recording.webm"
    webms[-1].replace(target_webm)
    for stray in video_dir.glob("*"):
        stray.unlink()
    video_dir.rmdir()
    print(f"Recorded: {target_webm.name}")

    target_mp4 = DEMO_DIR / "recording.mp4"
    subprocess.run(
        [
            "ffmpeg", "-y",
            "-i", str(target_webm),
            "-c:v", "libx264",
            "-pix_fmt", "yuv420p",
            "-crf", "20",
            "-preset", "fast",
            "-loglevel", "error",
            str(target_mp4),
        ],
        check=True,
    )
    print(f"Transcoded: {target_mp4.name}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
